{"path": "/tmp/sv-60fca9fd901746a18b8e0a13058b9ded/ContosoUniversity.Tests/Services/NotificationServiceTests.cs", "file_text": "using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Xunit;

namespace ContosoUniversity.Tests.Services;

public class NotificationServiceTests : IDisposable
{
    private readonly NotificationService _service;

    public NotificationServiceTests()
    {
        _service = new NotificationService();
        // Drain any leftover notifications from static queue
        while (_service.ReceiveNotification() != null) { }
    }

    public void Dispose()
    {
        _service.Dispose();
    }

    [Fact]
    public void SendNotification_WithDisplayName_EnqueuesNotification()
    {
        _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "admin");

        var notification = _service.ReceiveNotification();

        Assert.NotNull(notification);
        Assert.Equal("Student", notification.EntityType);
        Assert.Equal("1", notification.EntityId);
        Assert.Equal("CREATE", notification.Operation);
        Assert.Contains("John Doe", notification.Message);
        Assert.Contains("created", notification.Message);
        Assert.Equal("admin", notification.CreatedBy);
        Assert.False(notification.IsRead);
    }

    [Fact]
    public void SendNotification_WithoutDisplayName_UsesIdInMessage()
    {
        _service.SendNotification("Course", "42", null, EntityOperation.UPDATE, "teacher");

        var notification = _service.ReceiveNotification();

        Assert.NotNull(notification);
        Assert.Contains("ID: 42", notification.Message);
        Assert.Contains("updated", notification.Message);
    }

    [Fact]
    public void SendNotification_WithoutUserName_DefaultsToSystem()
    {
        _service.SendNotification("Department", "1", EntityOperation.DELETE);

        var notification = _service.ReceiveNotification();

        Assert.NotNull(notification);
        Assert.Equal("System", notification.CreatedBy);
    }

    [Fact]
    public void SendNotification_SimpleOverload_EnqueuesCorrectly()
    {
        _service.SendNotification("Instructor", "5", EntityOperation.CREATE);

        var notification = _service.ReceiveNotification();

        Assert.NotNull(notification);
        Assert.Equal("Instructor", notification.EntityType);
        Assert.Equal("5", notification.EntityId);
        Assert.Equal("CREATE", notification.Operation);
    }

    [Fact]
    public void ReceiveNotification_EmptyQueue_ReturnsNull()
    {
        var notification = _service.ReceiveNotification();

        Assert.Null(notification);
    }

    [Fact]
    public void ReceiveNotification_MultipleMessages_ReturnsFIFO()
    {
        _service.SendNotification("A", "1", "First", EntityOperation.CREATE);
        _service.SendNotification("B", "2", "Second", EntityOperation.UPDATE);
        _service.SendNotification("C", "3", "Third", EntityOperation.DELETE);

        var first = _service.ReceiveNotification();
        var second = _service.ReceiveNotification();
        var third = _service.ReceiveNotification();
        var empty = _service.ReceiveNotification();

        Assert.Equal("A", first!.EntityType);
        Assert.Equal("B", second!.EntityType);
        Assert.Equal("C", third!.EntityType);
        Assert.Null(empty);
    }

    [Fact]
    public void SendNotification_CreateOperation_MessageContainsCreated()
    {
        _service.SendNotification("Student", "1", "Test Student", EntityOperation.CREATE);
        var notification = _service.ReceiveNotification();

        Assert.Contains("has been created", notification!.Message);
        Assert.StartsWith("New", notification.Message);
    }

    [Fact]
    public void SendNotification_UpdateOperation_MessageContainsUpdated()
    {
        _service.SendNotification("Student", "1", "Test Student", EntityOperation.UPDATE);
        var notification = _service.ReceiveNotification();

        Assert.Contains("has been updated", notification!.Message);
    }

    [Fact]
    public void SendNotification_DeleteOperation_MessageContainsDeleted()
    {
        _service.SendNotification("Student", "1", "Test Student", EntityOperation.DELETE);
        var notification = _service.ReceiveNotification();

        Assert.Contains("has been deleted", notification!.Message);
    }

    [Fact]
    public void SendNotification_SetsCreatedAtToCurrentTime()
    {
        var before = DateTime.Now.AddSeconds(-1);
        _service.SendNotification("Student", "1", EntityOperation.CREATE);
        var after = DateTime.Now.AddSeconds(1);

        var notification = _service.ReceiveNotification();

        Assert.InRange(notification!.CreatedAt, before, after);
    }

    [Fact]
    public void MarkAsRead_DoesNotThrow()
    {
        // MarkAsRead is a no-op in the in-memory implementation
        var ex = Record.Exception(() => _service.MarkAsRead(999));
        Assert.Null(ex);
    }

    [Fact]
    public void Dispose_CanBeCalledMultipleTimes()
    {
        var service = new NotificationService();
        var ex = Record.Exception(() =>
        {
            service.Dispose();
            service.Dispose();
        });
        Assert.Null(ex);
    }
}
"}

{"path": "/tmp/sv-60fca9fd901746a18b8e0a13058b9ded/ContosoUniversity.Tests/Models/PaginatedListTests.cs", "file_text": "using Xunit;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests.Models;

public class PaginatedListTests
{
    [Fact]
    public void Constructor_SetsPageIndexAndTotalPages()
    {
        var items = new List<int> { 1, 2, 3 };
        var list = new PaginatedList<int>(items, 10, 2, 3);

        Assert.Equal(2, list.PageIndex);
        Assert.Equal(4, list.TotalPages); // ceil(10/3) = 4
    }

    [Fact]
    public void Constructor_AddsItemsToList()
    {
        var items = new List<string> { "a", "b", "c" };
        var list = new PaginatedList<string>(items, 5, 1, 3);

        Assert.Equal(3, list.Count);
        Assert.Contains("a", list);
        Assert.Contains("b", list);
        Assert.Contains("c", list);
    }

    [Fact]
    public void HasPreviousPage_FirstPage_ReturnsFalse()
    {
        var list = new PaginatedList<int>(new List<int> { 1 }, 10, 1, 5);
        Assert.False(list.HasPreviousPage);
    }

    [Fact]
    public void HasPreviousPage_SecondPage_ReturnsTrue()
    {
        var list = new PaginatedList<int>(new List<int> { 1 }, 10, 2, 5);
        Assert.True(list.HasPreviousPage);
    }

    [Fact]
    public void HasNextPage_LastPage_ReturnsFalse()
    {
        var list = new PaginatedList<int>(new List<int> { 1 }, 10, 2, 5);
        // TotalPages = ceil(10/5) = 2, pageIndex = 2
        Assert.False(list.HasNextPage);
    }

    [Fact]
    public void HasNextPage_NotLastPage_ReturnsTrue()
    {
        var list = new PaginatedList<int>(new List<int> { 1 }, 10, 1, 5);
        // TotalPages = ceil(10/5) = 2, pageIndex = 1
        Assert.True(list.HasNextPage);
    }

    [Fact]
    public void Create_ReturnsCorrectPage()
    {
        var source = Enumerable.Range(1, 20).AsQueryable();

        var page1 = PaginatedList<int>.Create(source, 1, 5);
        var page2 = PaginatedList<int>.Create(source, 2, 5);

        Assert.Equal(5, page1.Count);
        Assert.Equal(new[] { 1, 2, 3, 4, 5 }, page1.ToArray());
        Assert.Equal(new[] { 6, 7, 8, 9, 10 }, page2.ToArray());
    }

    [Fact]
    public void Create_SetsTotalPagesCorrectly()
    {
        var source = Enumerable.Range(1, 13).AsQueryable();
        var list = PaginatedList<int>.Create(source, 1, 5);

        Assert.Equal(3, list.TotalPages); // ceil(13/5) = 3
    }

    [Fact]
    public void Create_LastPageHasRemainingItems()
    {
        var source = Enumerable.Range(1, 13).AsQueryable();
        var lastPage = PaginatedList<int>.Create(source, 3, 5);

        Assert.Equal(3, lastPage.Count); // 13 - 10 = 3
        Assert.Equal(new[] { 11, 12, 13 }, lastPage.ToArray());
    }

    [Fact]
    public void Create_SinglePageContent()
    {
        var source = Enumerable.Range(1, 3).AsQueryable();
        var list = PaginatedList<int>.Create(source, 1, 10);

        Assert.Equal(1, list.TotalPages);
        Assert.Equal(1, list.PageIndex);
        Assert.False(list.HasPreviousPage);
        Assert.False(list.HasNextPage);
    }

    [Fact]
    public void TotalPages_RoundsUpCorrectly()
    {
        // 1 item, page size 10 => 1 page
        var list1 = new PaginatedList<int>(new List<int> { 1 }, 1, 1, 10);
        Assert.Equal(1, list1.TotalPages);

        // 11 items, page size 10 => 2 pages
        var list2 = new PaginatedList<int>(new List<int>(), 11, 1, 10);
        Assert.Equal(2, list2.TotalPages);

        // 10 items, page size 10 => 1 page
        var list3 = new PaginatedList<int>(new List<int>(), 10, 1, 10);
        Assert.Equal(1, list3.TotalPages);
    }
}
"}

