using Xunit;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests.Models;

public class PaginatedListTests
{
    [Fact]
    public void Constructor_SetsPageIndexAndTotalPages()
    {
        var items = new List<int> { 1, 2, 3 };
        var list = new PaginatedList<int>(items, 10, 2, 3);

        Assert.Equal(2, list.PageIndex);
        Assert.Equal(4, list.TotalPages); // ceil(10/3) = 4
    }

    [Fact]
    public void Constructor_AddsItemsToList()
    {
        var items = new List<string> { "a", "b", "c" };
        var list = new PaginatedList<string>(items, 5, 1, 3);

        Assert.Equal(3, list.Count);
        Assert.Contains("a", list);
        Assert.Contains("b", list);
        Assert.Contains("c", list);
    }

    [Fact]
    public void HasPreviousPage_FirstPage_ReturnsFalse()
    {
        var list = new PaginatedList<int>(new List<int> { 1 }, 10, 1, 5);
        Assert.False(list.HasPreviousPage);
    }

    [Fact]
    public void HasPreviousPage_SecondPage_ReturnsTrue()
    {
        var list = new PaginatedList<int>(new List<int> { 1 }, 10, 2, 5);
        Assert.True(list.HasPreviousPage);
    }

    [Fact]
    public void HasNextPage_LastPage_ReturnsFalse()
    {
        var list = new PaginatedList<int>(new List<int> { 1 }, 10, 2, 5);
        // TotalPages = ceil(10/5) = 2, pageIndex = 2
        Assert.False(list.HasNextPage);
    }

    [Fact]
    public void HasNextPage_NotLastPage_ReturnsTrue()
    {
        var list = new PaginatedList<int>(new List<int> { 1 }, 10, 1, 5);
        // TotalPages = ceil(10/5) = 2, pageIndex = 1
        Assert.True(list.HasNextPage);
    }

    [Fact]
    public void Create_ReturnsCorrectPage()
    {
        var source = Enumerable.Range(1, 20).AsQueryable();

        var page1 = PaginatedList<int>.Create(source, 1, 5);
        var page2 = PaginatedList<int>.Create(source, 2, 5);

        Assert.Equal(5, page1.Count);
        Assert.Equal(new[] { 1, 2, 3, 4, 5 }, page1.ToArray());
        Assert.Equal(new[] { 6, 7, 8, 9, 10 }, page2.ToArray());
    }

    [Fact]
    public void Create_SetsTotalPagesCorrectly()
    {
        var source = Enumerable.Range(1, 13).AsQueryable();
        var list = PaginatedList<int>.Create(source, 1, 5);

        Assert.Equal(3, list.TotalPages); // ceil(13/5) = 3
    }

    [Fact]
    public void Create_LastPageHasRemainingItems()
    {
        var source = Enumerable.Range(1, 13).AsQueryable();
        var lastPage = PaginatedList<int>.Create(source, 3, 5);

        Assert.Equal(3, lastPage.Count); // 13 - 10 = 3
        Assert.Equal(new[] { 11, 12, 13 }, lastPage.ToArray());
    }

    [Fact]
    public void Create_SinglePageContent()
    {
        var source = Enumerable.Range(1, 3).AsQueryable();
        var list = PaginatedList<int>.Create(source, 1, 10);

        Assert.Equal(1, list.TotalPages);
        Assert.Equal(1, list.PageIndex);
        Assert.False(list.HasPreviousPage);
        Assert.False(list.HasNextPage);
    }

    [Fact]
    public void TotalPages_RoundsUpCorrectly()
    {
        // 1 item, page size 10 => 1 page
        var list1 = new PaginatedList<int>(new List<int> { 1 }, 1, 1, 10);
        Assert.Equal(1, list1.TotalPages);

        // 11 items, page size 10 => 2 pages
        var list2 = new PaginatedList<int>(new List<int>(), 11, 1, 10);
