using ContosoUniversity.Models;
using System;
using System.Collections.Generic;
using System.ComponentModel.DataAnnotations;
using Xunit;

namespace ContosoUniversity.Tests.Models;

public class ModelValidationTests
{
    private static IList<ValidationResult> ValidateModel(object model)
    {
        var results = new List<ValidationResult>();
        var ctx = new ValidationContext(model);
        Validator.TryValidateObject(model, ctx, results, true);
        return results;
    }

    [Fact]
    public void Student_ValidModel_PassesValidation()
    {
        var student = new Student
        {
            LastName = "Smith",
            FirstMidName = "John",
            EnrollmentDate = new DateTime(2020, 9, 1)
        };

        var results = ValidateModel(student);
        Assert.Empty(results);
    }

    [Fact]
    public void Student_MissingLastName_FailsValidation()
    {
        var student = new Student
        {
            FirstMidName = "John",
            EnrollmentDate = new DateTime(2020, 9, 1)
        };

        var results = ValidateModel(student);
        Assert.Contains(results, r => r.MemberNames.Contains("LastName"));
    }

    [Fact]
    public void Student_MissingFirstName_FailsValidation()
    {
        var student = new Student
        {
            LastName = "Smith",
            EnrollmentDate = new DateTime(2020, 9, 1)
        };

        var results = ValidateModel(student);
        Assert.Contains(results, r => r.MemberNames.Contains("FirstMidName"));
    }

    [Fact]
    public void Student_LastNameTooLong_FailsValidation()
    {
        var student = new Student
        {
            LastName = new string('A', 51),
            FirstMidName = "John",
            EnrollmentDate = new DateTime(2020, 9, 1)
        };

        var results = ValidateModel(student);
        Assert.Contains(results, r => r.MemberNames.Contains("LastName"));
    }

    [Fact]
    public void Student_FirstNameTooLong_FailsValidation()
    {
        var student = new Student
        {
            LastName = "Smith",
            FirstMidName = new string('A', 51),
            EnrollmentDate = new DateTime(2020, 9, 1)
        };

        var results = ValidateModel(student);
        Assert.Contains(results, r => r.MemberNames.Contains("FirstMidName"));
    }

    [Fact]
    public void Person_FullName_ReturnsLastNameCommaFirstName()
    {
        var student = new Student { LastName = "Smith", FirstMidName = "John" };
        Assert.Equal("Smith, John", student.FullName);
    }

    [Fact]
    public void Course_ValidModel_PassesValidation()
    {
        var course = new Course
        {
            CourseID = 1050,
            Title = "Chemistry",
            Credits = 3,
            DepartmentID = 1
        };

        var results = ValidateModel(course);
        Assert.Empty(results);
    }

    [Fact]
    public void Course_TitleTooShort_FailsValidation()
    {
        var course = new Course
        {
            CourseID = 1050,
            Title = "AB",
            Credits = 3,
            DepartmentID = 1
        };

        var results = ValidateModel(course);
        Assert.Contains(results, r => r.MemberNames.Contains("Title"));
    }

    [Fact]
    public void Course_TitleTooLong_FailsValidation()
    {
        var course = new Course
        {
            CourseID = 1050,
            Title = new string('A', 51),
            Credits = 3,
            DepartmentID = 1
        };

        var results = ValidateModel(course);
        Assert.Contains(results, r => r.MemberNames.Contains("Title"));
    }

    [Fact]
    public void Course_CreditsOutOfRange_FailsValidation()
    {
        var course = new Course
        {
            CourseID = 1050,
            Title = "Chemistry",
            Credits = 6,
            DepartmentID = 1
        };

        var results = ValidateModel(course);
        Assert.Contains(results, r => r.MemberNames.Contains("Credits"));
    }

    [Fact]
    public void Course_CreditsNegative_FailsValidation()
    {
        var course = new Course
        {
            CourseID = 1050,
            Title = "Chemistry",
            Credits = -1,
            DepartmentID = 1
        };

        var results = ValidateModel(course);
        Assert.Contains(results, r => r.MemberNames.Contains("Credits"));
    }

    [Fact]
    public void Department_ValidModel_PassesValidation()
    {
        var dept = new Department
        {
            Name = "Engineering",
            Budget = 250000,
            StartDate = new DateTime(2007, 9, 1)
        };

        var results = ValidateModel(dept);
        Assert.Empty(results);
    }

    [Fact]
    public void Department_NameTooShort_FailsValidation()
    {
        var dept = new Department
        {
            Name = "AB",
            Budget = 250000,
            StartDate = new DateTime(2007, 9, 1)
        };

        var results = ValidateModel(dept);
        Assert.Contains(results, r => r.MemberNames.Contains("Name"));
    }

    [Fact]
    public void Department_NameTooLong_FailsValidation()
    {
        var dept = new Department
        {
            Name = new string('A', 51),
            Budget = 250000,
            StartDate = new DateTime(2007, 9, 1)
        };

        var results = ValidateModel(dept);
        Assert.Contains(results, r => r.MemberNames.Contains("Name"));
    }

    [Fact]
    public void Instructor_ValidModel_PassesValidation()
    {
        var instructor = new Instructor
        {
            LastName = "Harui",
            FirstMidName = "Roger",
            HireDate = new DateTime(1998, 7, 1)
        };

        var results = ValidateModel(instructor);
        Assert.Empty(results);
    }

    [Fact]
    public void Instructor_FullName_ReturnsCorrectFormat()
    {
        var instructor = new Instructor { LastName = "Harui", FirstMidName = "Roger" };
        Assert.Equal("Harui, Roger", instructor.FullName);
    }

    [Fact]
    public void Notification_ValidModel_PassesValidation()
    {
        var notification = new Notification
        {
            EntityType = "Student",
            EntityId = "1",
            Operation = "CREATE",
            Message = "New student created",
            CreatedAt = DateTime.Now
        };

        var results = ValidateModel(notification);
        Assert.Empty(results);
    }

    [Fact]
    public void Notification_MissingEntityType_FailsValidation()
    {
        var notification = new Notification
        {
            EntityId = "1",
            Operation = "CREATE",
            Message = "Test",
            CreatedAt = DateTime.Now
        };

        var results = ValidateModel(notification);
        Assert.Contains(results, r => r.MemberNames.Contains("EntityType"));
    }

    [Fact]
    public void OfficeAssignment_LocationTooLong_FailsValidation()
    {
        var office = new OfficeAssignment
        {
            InstructorID = 1,
            Location = new string('A', 51)
        };

        var results = ValidateModel(office);
        Assert.Contains(results, r => r.MemberNames.Contains("Location"));
    }

    [Fact]
    public void Enrollment_GradeIsNullable()
    {
        var enrollment = new Enrollment
        {
            CourseID = 1,
            StudentID = 1,
            Grade = null
        };

        Assert.Null(enrollment.Grade);
    }

    [Fact]
    public void Enrollment_AllGradesAreValid()
    {
        foreach (Grade grade in Enum.GetValues(typeof(Grade)))
        {
            var enrollment = new Enrollment { Grade = grade };
            Assert.Equal(grade, enrollment.Grade);
        }
    }
}

