using Xunit;

namespace ContosoUniversity.Tests.Controllers;

public class StudentsControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly StudentsController _controller;

    public StudentsControllerTests()
    {
        _context = TestHelpers.CreateInMemoryContext();
        TestHelpers.SeedStudents(_context);
        _controller = CreateController();
    }

    private StudentsController CreateController()
    {
        var controller = new StudentsController(_context);
        controller.ControllerContext = new ControllerContext
        {
            HttpContext = new DefaultHttpContext()
        };
        controller.TempData = new TempDataDictionary(
            controller.ControllerContext.HttpContext,
            new SessionStateTempDataProvider(new SessionStateTempDataSerializer()));
        return controller;
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    [Fact]
    public void Index_NoParams_ReturnsViewWithAllStudents()
    {
        var result = _controller.Index(null, null, null, null) as ViewResult;

        Assert.NotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.NotNull(model);
        Assert.Equal(5, model.Count);
    }

    [Fact]
    public void Index_SortByNameDesc_ReturnsSortedStudents()
    {
        var result = _controller.Index("name_desc", null, null, null) as ViewResult;

        var model = result!.Model as PaginatedList<Student>;
        Assert.Equal("Li", model![0].LastName);
    }

    [Fact]
    public void Index_SortByDate_ReturnsSortedByDate()
    {
        var result = _controller.Index("Date", null, null, null) as ViewResult;

        var model = result!.Model as PaginatedList<Student>;
        Assert.NotNull(model);
        // Earliest date first
        Assert.True(model[0].EnrollmentDate <= model[1].EnrollmentDate);
    }

    [Fact]
    public void Index_SortByDateDesc_ReturnsSortedByDateDescending()
    {
        var result = _controller.Index("date_desc", null, null, null) as ViewResult;

        var model = result!.Model as PaginatedList<Student>;
        Assert.NotNull(model);
        Assert.True(model[0].EnrollmentDate >= model[1].EnrollmentDate);
    }

    [Fact]
    public void Index_SearchByLastName_FiltersResults()
    {
        var result = _controller.Index(null, null, "Alexander", null) as ViewResult;

        var model = result!.Model as PaginatedList<Student>;
        Assert.Single(model!);
        Assert.Equal("Alexander", model[0].LastName);
    }

    [Fact]
    public void Index_SearchByFirstName_FiltersResults()
    {
        var result = _controller.Index(null, null, "Carson", null) as ViewResult;

        var model = result!.Model as PaginatedList<Student>;
        Assert.Single(model!);
        Assert.Equal("Carson", model[0].FirstMidName);
    }

    [Fact]
    public void Index_SearchResetsToPage1()
    {
        var result = _controller.Index(null, null, "A", 5) as ViewResult;

        var model = result!.Model as PaginatedList<Student>;
        Assert.Equal(1, model!.PageIndex);
    }

    [Fact]
    public void Index_CurrentFilter_UsedWhenSearchStringNull()
    {
        var result = _controller.Index(null, "Alexander", null, null) as ViewResult;

        var model = result!.Model as PaginatedList<Student>;
        Assert.Single(model!);
    }

    [Fact]
    public void Index_SetsViewBagSortParameters()
    {
        _controller.Index(null, null, null, null);

        Assert.Equal("name_desc", _controller.ViewBag.NameSortParm);
        Assert.Equal("Date", _controller.ViewBag.DateSortParm);
    }

    [Fact]
    public void Index_WithSortOrder_InvertsNameSortParm()
    {
        _controller.Index("name_desc", null, null, null);

        Assert.Equal("", _controller.ViewBag.NameSortParm);
    }

