namespace ContosoUniversity.Tests.Controllers;

public class NotificationsControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly NotificationsController _controller;

    public NotificationsControllerTests()
    {
        _context = TestHelpers.CreateInMemoryContext();
        _controller = CreateController();
    }

    private NotificationsController CreateController()
    {
        var controller = new NotificationsController(_context);
        controller.ControllerContext = new ControllerContext
        {
            HttpContext = new DefaultHttpContext()
        };
        controller.TempData = new TempDataDictionary(
            controller.ControllerContext.HttpContext,
            new SessionStateTempDataProvider(new SessionStateTempDataSerializer()));
        return controller;
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    [Fact]
    public void GetNotifications_EmptyQueue_ReturnsSuccessWithZeroCount()
    {
        var result = _controller.GetNotifications();

        Assert.NotNull(result);
        var json = result.Value;
        Assert.NotNull(json);
        // Verify it's a valid JsonResult with success = true
        var successProp = json.GetType().GetProperty("success");
        Assert.True((bool)successProp!.GetValue(json)!);
    }

    [Fact]
    public void Index_ReturnsView()
    {
        var result = _controller.Index() as ViewResult;
        Assert.NotNull(result);
    }

    [Fact]
    public void MarkAsRead_ValidId_ReturnsSuccess()
    {
        var result = _controller.MarkAsRead(1);

        Assert.NotNull(result);
        var json = result.Value;
        Assert.NotNull(json);
        var successProp = json.GetType().GetProperty("success");
        Assert.True((bool)successProp!.GetValue(json)!);
    }

    [Fact]
    public void GetNotifications_WithQueuedNotifications_ReturnsNotifications()
    {
        // Use a StudentsController to send notifications (which enqueues them)
        var studentsController = new StudentsController(_context);
        studentsController.ControllerContext = new ControllerContext
        {
            HttpContext = new DefaultHttpContext()
        };
        studentsController.TempData = new TempDataDictionary(
            studentsController.ControllerContext.HttpContext,
            new SessionStateTempDataProvider(new SessionStateTempDataSerializer()));

        // Create a student to trigger notification
        TestHelpers.SeedStudents(_context);

        var student = new Student
        {
            LastName = "NotifyTest",
            FirstMidName = "User",
            EnrollmentDate = new DateTime(2023, 1, 1)
        };
        studentsController.Create(student);

        // Now get notifications
        var result = _controller.GetNotifications();
        Assert.NotNull(result);

        studentsController.Dispose();
    }
}
