using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Microsoft.EntityFrameworkCore;
using System;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers;

public class DepartmentsControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly DepartmentsController _controller;

    public DepartmentsControllerTests()
    {
        _context = TestHelpers.CreateInMemoryContext();
        TestHelpers.SeedDepartments(_context);
        TestHelpers.SeedInstructors(_context);
        _controller = CreateController();
    }

    private DepartmentsController CreateController()
    {
        var controller = new DepartmentsController(_context);
        controller.ControllerContext = new ControllerContext
        {
            HttpContext = new DefaultHttpContext()
        };
        controller.TempData = new TempDataDictionary(
            controller.ControllerContext.HttpContext,
            new SessionStateTempDataProvider(new SessionStateTempDataSerializer()));
        return controller;
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    [Fact]
    public void Index_ReturnsViewWithAllDepartments()
    {
        var result = _controller.Index() as ViewResult;

        Assert.NotNull(result);
        var model = result.Model as System.Collections.Generic.List<Department>;
        Assert.NotNull(model);
        Assert.Equal(3, model.Count);
    }

    [Fact]
    public void Details_ValidId_ReturnsViewWithDepartment()
    {
        var result = _controller.Details(1) as ViewResult;

        Assert.NotNull(result);
        var model = result.Model as Department;
        Assert.NotNull(model);
        Assert.Equal("English", model.Name);
    }

    [Fact]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null) as StatusCodeResult;

        Assert.NotNull(result);
        Assert.Equal(400, result.StatusCode);
    }

    [Fact]
    public void Details_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Details(999) as NotFoundResult;

        Assert.NotNull(result);
    }

    [Fact]
    public void Create_Get_ReturnsViewWithInstructorSelectList()
    {
        var result = _controller.Create() as ViewResult;

        Assert.NotNull(result);
        Assert.NotNull(_controller.ViewBag.InstructorID);
    }

    [Fact]
    public void Create_Post_ValidDepartment_RedirectsToIndex()
    {
        var dept = new Department
        {
            Name = "Physics",
            Budget = 200000,
            StartDate = DateTime.Parse("2020-09-01")
        };

        var result = _controller.Create(dept) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
    }

    [Fact]
    public void Create_Post_ValidDepartment_SavesDepartment()
    {
        var dept = new Department
        {
            Name = "Physics",
            Budget = 200000,
            StartDate = DateTime.Parse("2020-09-01")
        };

        _controller.Create(dept);

        Assert.Contains(_context.Departments, d => d.Name == "Physics");
    }

    [Fact]
    public void Create_Post_InvalidModel_ReturnsView()
    {
        _controller.ModelState.AddModelError("Name", "Required");
        var dept = new Department();

        var result = _controller.Create(dept) as ViewResult;

        Assert.NotNull(result);
    }

    [Fact]
    public void Edit_Get_ValidId_ReturnsViewWithDepartment()
    {
        var result = _controller.Edit(1) as ViewResult;

        Assert.NotNull(result);
        var model = result.Model as Department;
        Assert.NotNull(model);
        Assert.Equal("English", model.Name);
    }

    [Fact]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        var result = _controller.Edit(null) as StatusCodeResult;

        Assert.NotNull(result);
        Assert.Equal(400, result.StatusCode);
    }

    [Fact]
    public void Edit_Get_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Edit(999) as NotFoundResult;

        Assert.NotNull(result);
    }

    [Fact]
    public void Edit_Post_ValidDepartment_RedirectsToIndex()
    {
        var dept = _context.Departments.AsNoTracking().First(d => d.DepartmentID == 1);
        dept.Name = "Updated English";

        var result = _controller.Edit(dept) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
    }

    [Fact]
    public void Edit_Post_InvalidModel_ReturnsView()
    {
        _controller.ModelState.AddModelError("Name", "Error");
        var dept = new Department { DepartmentID = 1 };

        var result = _controller.Edit(dept) as ViewResult;

        Assert.NotNull(result);
    }

    [Fact]
    public void Delete_Get_ValidId_ReturnsViewWithDepartment()
    {
        var result = _controller.Delete(1) as ViewResult;

        Assert.NotNull(result);
        var model = result.Model as Department;
        Assert.NotNull(model);
        Assert.Equal("English", model.Name);
    }

    [Fact]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        var result = _controller.Delete(null) as StatusCodeResult;

        Assert.NotNull(result);
        Assert.Equal(400, result.StatusCode);
    }

    [Fact]
    public void Delete_Get_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Delete(999) as NotFoundResult;

        Assert.NotNull(result);
    }

    [Fact]
    public void DeleteConfirmed_ValidId_RemovesAndRedirects()
    {
        var result = _controller.DeleteConfirmed(1) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
        Assert.DoesNotContain(_context.Departments, d => d.DepartmentID == 1);
    }
}

