using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Logging;
using Moq;
using System;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers;

public class CoursesControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly CoursesController _controller;
    private readonly Mock<IWebHostEnvironment> _mockEnv;
    private readonly Mock<ILogger<CoursesController>> _mockLogger;

    public CoursesControllerTests()
    {
        _context = TestHelpers.CreateInMemoryContext();
        TestHelpers.SeedCourses(_context);
        _mockEnv = new Mock<IWebHostEnvironment>();
        _mockEnv.Setup(e => e.WebRootPath).Returns("/tmp/webroot");
        _mockEnv.Setup(e => e.ContentRootPath).Returns("/tmp/content");
        _mockLogger = new Mock<ILogger<CoursesController>>();
        _controller = CreateController();
    }

    private CoursesController CreateController()
    {
        var controller = new CoursesController(_context, _mockEnv.Object, _mockLogger.Object);
        controller.ControllerContext = new ControllerContext
        {
            HttpContext = new DefaultHttpContext()
        };
        controller.TempData = new TempDataDictionary(
            controller.ControllerContext.HttpContext,
            new SessionStateTempDataProvider(new SessionStateTempDataSerializer()));
        return controller;
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    [Fact]
    public void Index_ReturnsViewWithAllCourses()
    {
        var result = _controller.Index() as ViewResult;

        Assert.NotNull(result);
        var model = result.Model as System.Collections.Generic.List<Course>;
        Assert.NotNull(model);
        Assert.Equal(3, model.Count);
    }

    [Fact]
    public void Details_ValidId_ReturnsViewWithCourse()
    {
        var result = _controller.Details(1050) as ViewResult;

        Assert.NotNull(result);
        var model = result.Model as Course;
        Assert.NotNull(model);
        Assert.Equal("Chemistry", model.Title);
    }

    [Fact]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null) as StatusCodeResult;

        Assert.NotNull(result);
        Assert.Equal(400, result.StatusCode);
    }

    [Fact]
    public void Create_Get_ReturnsViewWithDepartmentSelectList()
    {
        var result = _controller.Create() as ViewResult;

        Assert.NotNull(result);
        Assert.NotNull(_controller.ViewBag.DepartmentID);
        var model = result.Model as Course;
        Assert.NotNull(model);
    }

    [Fact]
    public void Create_Post_ValidCourse_RedirectsToIndex()
    {
        var course = new Course
        {
            CourseID = 9999,
            Title = "New Course",
            Credits = 4,
            DepartmentID = 1
        };

        var result = _controller.Create(course, null!) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
    }

    [Fact]
    public void Create_Post_ValidCourse_SavesCourse()
    {
        var course = new Course
        {
            CourseID = 8888,
            Title = "Saved Course",
            Credits = 2,
            DepartmentID = 1
        };

        _controller.Create(course, null!);

        Assert.Contains(_context.Courses, c => c.CourseID == 8888);
    }

    [Fact]
    public void Create_Post_InvalidModel_ReturnsView()
    {
        _controller.ModelState.AddModelError("Title", "Required");
        var course = new Course { CourseID = 7777 };

        var result = _controller.Create(course, null!) as ViewResult;

        Assert.NotNull(result);
    }

    [Fact]
    public void Create_Post_WithInvalidFileExtension_ReturnsViewWithError()
    {
        var course = new Course
        {
            CourseID = 6666,
            Title = "Test Course",
            Credits = 3,
            DepartmentID = 1
        };

        var mockFile = new Mock<IFormFile>();
        mockFile.Setup(f => f.FileName).Returns("document.txt");
        mockFile.Setup(f => f.Length).Returns(1024);

        var result = _controller.Create(course, mockFile.Object) as ViewResult;

        Assert.NotNull(result);
        Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    [Fact]
    public void Create_Post_WithOversizedFile_ReturnsViewWithError()
    {
        var course = new Course
        {
            CourseID = 5555,
            Title = "Test Course",
            Credits = 3,
            DepartmentID = 1
        };

        var mockFile = new Mock<IFormFile>();
        mockFile.Setup(f => f.FileName).Returns("image.jpg");
        mockFile.Setup(f => f.Length).Returns(6 * 1024 * 1024); // 6MB > 5MB limit

        var result = _controller.Create(course, mockFile.Object) as ViewResult;

        Assert.NotNull(result);
        Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    [Fact]
    public void Edit_Get_ValidId_ReturnsViewWithCourse()
    {
        var result = _controller.Edit(1050) as ViewResult;

        Assert.NotNull(result);
        var model = result.Model as Course;
        Assert.NotNull(model);
        Assert.Equal("Chemistry", model.Title);
        Assert.NotNull(_controller.ViewBag.DepartmentID);
    }

    [Fact]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        var result = _controller.Edit(null) as StatusCodeResult;

        Assert.NotNull(result);
        Assert.Equal(400, result.StatusCode);
    }

    [Fact]
    public void Edit_Get_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Edit(9999) as NotFoundResult;

        Assert.NotNull(result);
    }

    [Fact]
    public void Edit_Post_ValidCourse_RedirectsToIndex()
    {
        var course = _context.Courses.AsNoTracking().First(c => c.CourseID == 1050);
        course.Title = "Updated Chemistry";

        var result = _controller.Edit(course, null!) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
    }

    [Fact]
    public void Edit_Post_InvalidModel_ReturnsView()
    {
        _controller.ModelState.AddModelError("Title", "Error");
        var course = new Course { CourseID = 1050 };

        var result = _controller.Edit(course, null!) as ViewResult;

        Assert.NotNull(result);
    }

    [Fact]
    public void Edit_Post_WithInvalidFileExtension_ReturnsViewWithError()
    {
        var course = _context.Courses.AsNoTracking().First(c => c.CourseID == 1050);

        var mockFile = new Mock<IFormFile>();
        mockFile.Setup(f => f.FileName).Returns("file.exe");
        mockFile.Setup(f => f.Length).Returns(1024);

        var result = _controller.Edit(course, mockFile.Object) as ViewResult;

        Assert.NotNull(result);
        Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    [Fact]
    public void Delete_Get_ValidId_ReturnsViewWithCourse()
    {
        var result = _controller.Delete(1050) as ViewResult;

        Assert.NotNull(result);
        var model = result.Model as Course;
        Assert.NotNull(model);
        Assert.Equal("Chemistry", model.Title);
    }

    [Fact]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        var result = _controller.Delete(null) as StatusCodeResult;

        Assert.NotNull(result);
        Assert.Equal(400, result.StatusCode);
    }

    [Fact]
    public void DeleteConfirmed_ValidId_RemovesAndRedirects()
    {
        var result = _controller.DeleteConfirmed(1050) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
        Assert.DoesNotContain(_context.Courses, c => c.CourseID == 1050);
    }
}

