using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers;

public class InstructorsControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly InstructorsController _controller;

    public InstructorsControllerTests()
    {
        _context = TestHelpers.CreateInMemoryContext();
        TestHelpers.SeedFullData(_context);
        _controller = CreateController();
    }

    private InstructorsController CreateController()
    {
        var controller = new InstructorsController(_context);
        controller.ControllerContext = new ControllerContext
        {
            HttpContext = new DefaultHttpContext()
        };
        controller.TempData = new TempDataDictionary(
            controller.ControllerContext.HttpContext,
            new SessionStateTempDataProvider(new SessionStateTempDataSerializer()));
        return controller;
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    [Fact]
    public void Index_NoParams_ReturnsViewWithInstructors()
    {
        var result = _controller.Index(null, null) as ViewResult;

        Assert.NotNull(result);
        var model = result.Model as InstructorIndexData;
        Assert.NotNull(model);
        Assert.Equal(3, model.Instructors.Count());
    }

    [Fact]
    public void Index_WithInstructorId_LoadsCourses()
    {
        var result = _controller.Index(10, null) as ViewResult;

        var model = result!.Model as InstructorIndexData;
        Assert.NotNull(model!.Courses);
        Assert.Single(model.Courses);
    }

    [Fact]
    public void Index_WithCourseId_LoadsEnrollments()
    {
        var result = _controller.Index(10, 1050) as ViewResult;

        var model = result!.Model as InstructorIndexData;
        Assert.NotNull(model!.Enrollments);
        Assert.Single(model.Enrollments);
    }

    [Fact]
    public void Details_ValidId_ReturnsViewWithInstructor()
    {
        var result = _controller.Details(10) as ViewResult;

        Assert.NotNull(result);
        var model = result.Model as Instructor;
        Assert.NotNull(model);
        Assert.Equal("Abercrombie", model.LastName);
    }

    [Fact]
    public void Details_NullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null) as StatusCodeResult;

        Assert.NotNull(result);
        Assert.Equal(400, result.StatusCode);
    }

    [Fact]
    public void Details_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Details(999) as NotFoundResult;

        Assert.NotNull(result);
    }

    [Fact]
    public void Create_Get_ReturnsViewWithCourseData()
    {
        var result = _controller.Create() as ViewResult;

        Assert.NotNull(result);
        var model = result.Model as Instructor;
        Assert.NotNull(model);
        Assert.NotNull(model.CourseAssignments);
        Assert.NotNull(_controller.ViewBag.Courses);
    }

    [Fact]
    public void Create_Post_ValidInstructor_RedirectsToIndex()
    {
        var instructor = new Instructor
        {
            LastName = "NewInstructor",
            FirstMidName = "Test",
            HireDate = new DateTime(2020, 1, 1),
            CourseAssignments = new List<CourseAssignment>()
        };

        var result = _controller.Create(instructor, null!) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
    }

    [Fact]
    public void Create_Post_WithSelectedCourses_AssignsCourses()
    {
        var instructor = new Instructor
        {
            LastName = "WithCourses",
            FirstMidName = "Test",
            HireDate = new DateTime(2020, 1, 1),
            CourseAssignments = new List<CourseAssignment>()
        };

        _controller.Create(instructor, new[] { "1050", "4022" });

        var saved = _context.Instructors
            .Include(i => i.CourseAssignments)
            .First(i => i.LastName == "WithCourses");
        Assert.Equal(2, saved.CourseAssignments.Count);
    }

    [Fact]
    public void Create_Post_InvalidModel_ReturnsView()
    {
        _controller.ModelState.AddModelError("LastName", "Required");
        var instructor = new Instructor
        {
            HireDate = DateTime.Now,
            CourseAssignments = new List<CourseAssignment>()
        };

        var result = _controller.Create(instructor, null!) as ViewResult;

        Assert.NotNull(result);
    }

    [Fact]
    public void Edit_Get_ValidId_ReturnsViewWithInstructor()
    {
        var result = _controller.Edit(10) as ViewResult;

        Assert.NotNull(result);
        var model = result.Model as Instructor;
        Assert.NotNull(model);
        Assert.Equal("Abercrombie", model.LastName);
    }

    [Fact]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        var result = _controller.Edit((int?)null) as StatusCodeResult;

        Assert.NotNull(result);
        Assert.Equal(400, result.StatusCode);
    }

    [Fact]
    public void Delete_Get_ValidId_ReturnsViewWithInstructor()
    {
        var result = _controller.Delete(10) as ViewResult;

        Assert.NotNull(result);
        var model = result.Model as Instructor;
        Assert.NotNull(model);
        Assert.Equal("Abercrombie", model.LastName);
    }

    [Fact]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        var result = _controller.Delete(null) as StatusCodeResult;

        Assert.NotNull(result);
        Assert.Equal(400, result.StatusCode);
    }

    [Fact]
    public void Delete_Get_InvalidId_ReturnsNotFound()
    {
        var result = _controller.Delete(999) as NotFoundResult;

        Assert.NotNull(result);
    }

    [Fact]
    public void DeleteConfirmed_ValidId_RemovesAndRedirects()
    {
        // Use instructor 12 (no department association)
        var result = _controller.DeleteConfirmed(12) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
        Assert.DoesNotContain(_context.Instructors, i => i.ID == 12);
    }

    [Fact]
    public void DeleteConfirmed_InstructorAsDepartmentAdmin_NullsOutDepartmentAdmin()
    {
        // Assign instructor 10 as department administrator
        var dept = _context.Departments.First();
        dept.InstructorID = 10;
        _context.SaveChanges();

        _controller.DeleteConfirmed(10);

        var updatedDept = _context.Departments.First(d => d.DepartmentID == dept.DepartmentID);
        Assert.Null(updatedDept.InstructorID);
    }
}

