using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using System;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests;

public class SchoolContextTests : IDisposable
{
    private readonly SchoolContext _context;

    public SchoolContextTests()
    {
        _context = TestHelpers.CreateInMemoryContext();
    }

    public void Dispose()
    {
        _context.Dispose();
    }

    [Fact]
    public void CanAddAndRetrieveStudent()
    {
        var student = new Student
        {
            LastName = "Test",
            FirstMidName = "Student",
            EnrollmentDate = new DateTime(2023, 9, 1)
        };

        _context.Students.Add(student);
        _context.SaveChanges();

        var retrieved = _context.Students.First(s => s.LastName == "Test");
        Assert.Equal("Test", retrieved.LastName);
        Assert.Equal("Student", retrieved.FirstMidName);
    }

    [Fact]
    public void CanAddAndRetrieveCourse()
    {
        TestHelpers.SeedDepartments(_context);

        var course = new Course
        {
            CourseID = 1234,
            Title = "Test Course",
            Credits = 3,
            DepartmentID = 1
        };

        _context.Courses.Add(course);
        _context.SaveChanges();

        var retrieved = _context.Courses.Find(1234);
        Assert.NotNull(retrieved);
        Assert.Equal("Test Course", retrieved.Title);
    }

    [Fact]
    public void CanAddAndRetrieveDepartment()
    {
        var dept = new Department
        {
            Name = "TestDept",
            Budget = 100000,
            StartDate = new DateTime(2020, 1, 1)
        };

        _context.Departments.Add(dept);
        _context.SaveChanges();

        var retrieved = _context.Departments.First(d => d.Name == "TestDept");
        Assert.Equal(100000, retrieved.Budget);
    }

    [Fact]
    public void CanAddAndRetrieveInstructor()
    {
        var instructor = new Instructor
        {
            LastName = "TestInst",
            FirstMidName = "Test",
            HireDate = new DateTime(2020, 1, 1),
            CourseAssignments = new System.Collections.Generic.List<CourseAssignment>()
        };

        _context.Instructors.Add(instructor);
        _context.SaveChanges();

        var retrieved = _context.Instructors.First(i => i.LastName == "TestInst");
        Assert.Equal("TestInst", retrieved.LastName);
    }

    [Fact]
    public void CanCreateEnrollment()
    {
        TestHelpers.SeedCourses(_context);
        var student = new Student
        {
            LastName = "Enrolled",
            FirstMidName = "Stu",
            EnrollmentDate = DateTime.Now
        };
        _context.Students.Add(student);
        _context.SaveChanges();

        var enrollment = new Enrollment
        {
            CourseID = 1050,
            StudentID = student.ID,
            Grade = Grade.A
        };
        _context.Enrollments.Add(enrollment);
        _context.SaveChanges();

        var retrieved = _context.Enrollments.First(e => e.StudentID == student.ID);
        Assert.Equal(Grade.A, retrieved.Grade);
        Assert.Equal(1050, retrieved.CourseID);
    }

    [Fact]
    public void CourseAssignment_CompositeKey_Works()
    {
        TestHelpers.SeedFullData(_context);

        var assignment = _context.CourseAssignments
            .First(ca => ca.CourseID == 1050 && ca.InstructorID == 10);

        Assert.NotNull(assignment);
    }

    [Fact]
    public void CanNavigateStudentEnrollments()
    {
        TestHelpers.SeedFullData(_context);

        var student = _context.Students
            .Include(s => s.Enrollments)
            .First(s => s.ID == 1);

        Assert.NotNull(student.Enrollments);
        Assert.Equal(2, student.Enrollments.Count);
    }

    [Fact]
    public void CanNavigateCourseDepartment()
    {
        TestHelpers.SeedCourses(_context);

        var course = _context.Courses
            .Include(c => c.Department)
            .First(c => c.CourseID == 1050);

        Assert.NotNull(course.Department);
        Assert.Equal("English", course.Department.Name);
    }

    [Fact]
    public void DeleteStudent_RemovesFromDatabase()
    {
        TestHelpers.SeedStudents(_context);

        var student = _context.Students.First();
        _context.Students.Remove(student);
        _context.SaveChanges();

        Assert.Equal(4, _context.Students.Count());
    }
}

